module multi_8bit(
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] product,
    input [3:0] a,
    input [3:0] b,
    input cin,
    output [3:0] sum,
    output cout
);

reg [15:0] temp_product;
reg [3:0] i;

always @(*) begin
    temp_product = 16'b0;
    for (i = 0; i < 8; i = i + 1) begin
        if (B[i]) begin
            temp_product = temp_product + (A << i);
        end
    end
    product = temp_product;
end

endmodule
